import { existsSync, readdirSync, readFileSync } from "node:fs";
import { resolve } from "node:path";
import { describe, expect, it } from "vitest";
import {
	isServedPath,
	prefersJsonError,
	SERVED_EXACT,
	shouldJsonError,
} from "@/lib/agent-404";
import { SITE } from "@/lib/constants";
import { SEARCH_RESULTS_CSP, SEARCH_RESULTS_HTML } from "@/lib/mcp-ui";

describe("isServedPath", () => {
	it("real top-level pages are served", () => {
		for (const p of ["/", "/compare", "/alternatives", "/pricing", "/about"]) {
			expect(isServedPath(p)).toBe(true);
		}
	});

	it("prefix namespaces are served", () => {
		expect(isServedPath("/docs/foundations/overview")).toBe(true);
		expect(isServedPath("/api/mcp")).toBe(true);
		expect(isServedPath("/.well-known/agent-card.json")).toBe(true);
		expect(isServedPath("/_next/data/x.json")).toBe(true);
	});

	it("static-asset extensions are served (handled natively)", () => {
		expect(isServedPath("/favicon.svg")).toBe(true);
		expect(isServedPath("/thumbnails/x.png")).toBe(true);
	});

	it("unknown .json paths are NOT served (agents get a JSON 404)", () => {
		// /product_feed.json is an Agentic-Commerce probe; an HTML 404 there is the
		// lone content-negotiation leak (#2316 class). Real .json is in SERVED_EXACT.
		expect(isServedPath("/product_feed.json")).toBe(false);
		expect(shouldJsonError("GET", "/product_feed.json", "*/*")).toBe(true);
		// served .json (rewritten handler) is still never hijacked
		expect(isServedPath("/.well-known/agent-card.json")).toBe(true);
		expect(isServedPath("/_next/data/x.json")).toBe(true);
	});

	it("unknown root paths are NOT served (true 404s)", () => {
		for (const p of [
			"/checkout_sessions",
			"/delegate_payment",
			"/.well-known/oauth-authorization-server",
			"/random-nonsense",
		]) {
			expect(isServedPath(p)).toBe(false);
		}
	});
});

describe("prefersJsonError", () => {
	it("a browser asking for HTML does not prefer JSON", () => {
		expect(prefersJsonError("text/html,application/xhtml+xml")).toBe(false);
	});

	it("*/* and JSON-typed accepts prefer JSON", () => {
		expect(prefersJsonError("*/*")).toBe(true);
		expect(prefersJsonError("application/json")).toBe(true);
		expect(prefersJsonError("")).toBe(true);
	});
});

describe("shouldJsonError", () => {
	it("unknown path + non-browser client → JSON 404", () => {
		expect(shouldJsonError("GET", "/checkout_sessions", "*/*")).toBe(true);
		expect(
			shouldJsonError("POST", "/delegate_payment", "application/json"),
		).toBe(true);
	});

	it("unknown path + browser → fall through to HTML 404", () => {
		expect(shouldJsonError("GET", "/checkout_sessions", "text/html")).toBe(
			false,
		);
	});

	it("served path is never hijacked", () => {
		expect(shouldJsonError("GET", "/compare", "*/*")).toBe(false);
		expect(shouldJsonError("GET", "/api/mcp", "application/json")).toBe(false);
	});

	it("CORS preflight (OPTIONS) is never hijacked", () => {
		expect(shouldJsonError("OPTIONS", "/checkout_sessions", "")).toBe(false);
	});
});

// Drift guard: every real page in the (home) route group must be allowlisted,
// or an agent requesting it as JSON would get a spurious 404. Derives the routes
// from the filesystem so adding a marketing page without updating SERVED_EXACT
// fails here instead of in production.
describe("SERVED_EXACT covers the (home) route group", () => {
	const homeDir = resolve(__dirname, "../app/(home)");

	function homePaths(dir: string, base = ""): string[] {
		const out: string[] = [];
		for (const entry of readdirSync(dir, { withFileTypes: true })) {
			if (!entry.isDirectory()) continue;
			const sub = resolve(dir, entry.name);
			if (existsSync(resolve(sub, "page.tsx"))) {
				out.push(`${base}/${entry.name}`);
			}
			out.push(...homePaths(sub, `${base}/${entry.name}`));
		}
		return out;
	}

	it("each (home) page path is in SERVED_EXACT", () => {
		// The route group itself maps to "/", plus one entry per nested page dir.
		const paths = existsSync(resolve(homeDir, "page.tsx"))
			? ["/", ...homePaths(homeDir)]
			: homePaths(homeDir);
		for (const p of paths) {
			expect(SERVED_EXACT.has(p), `missing from SERVED_EXACT: ${p}`).toBe(true);
		}
	});

	it("every top-level dotted route-file dir in app/ is allowlisted", () => {
		// auth.md/, llms.txt/, api-policy.md/, ... — route handlers whose dir name
		// contains a dot serve an exact path. The extension fallback in
		// isServedPath() masks omissions in production, so this guard keeps the
		// hand-maintained list honest (caught /api-policy.md drifting in #2385).
		const appDir = resolve(__dirname, "../app");
		for (const entry of readdirSync(appDir, { withFileTypes: true })) {
			if (!entry.isDirectory() || !entry.name.includes(".")) continue;
			if (!existsSync(resolve(appDir, entry.name, "route.ts"))) continue;
			expect(
				SERVED_EXACT.has(`/${entry.name}`),
				`route dir not allowlisted: /${entry.name}`,
			).toBe(true);
		}
	});

	it("every /.well-known rewrite in next.config is allowlisted", () => {
		const cfg = readFileSync(resolve(__dirname, "../next.config.mjs"), "utf8");
		const sources = [...cfg.matchAll(/source:\s*"(\/\.well-known[^"]*)"/g)].map(
			(m) => m[1],
		);
		expect(sources.length).toBeGreaterThan(0);
		for (const s of sources) {
			expect(SERVED_EXACT.has(s), `well-known rewrite not allowlisted: ${s}`).toBe(
				true,
			);
		}
	});
});

describe("MCP App view CSP (orank UX check)", () => {
	it("scopes all four directive categories", () => {
		expect(SEARCH_RESULTS_CSP).toContain(`connect-src ${SITE.domain}`);
		expect(SEARCH_RESULTS_CSP).toContain(
			"frame-ancestors https://chatgpt.com https://claude.ai",
		);
		expect(SEARCH_RESULTS_CSP).toContain("form-action");
		expect(SEARCH_RESULTS_CSP).toMatch(/img-src \S/);
	});

	it("never uses a bare wildcard source", () => {
		// orank docks points for `*`; every directive must list specific origins.
		expect(SEARCH_RESULTS_CSP).not.toMatch(/(^|\s)\*/);
		expect(SEARCH_RESULTS_CSP).not.toContain("'unsafe-eval'");
	});

	it("is embedded in the App view HTML via <meta http-equiv>", () => {
		expect(SEARCH_RESULTS_HTML).toContain(
			'<meta http-equiv="Content-Security-Policy"',
		);
		expect(SEARCH_RESULTS_HTML).toContain(SEARCH_RESULTS_CSP);
	});
});
